def verify(subject: str, predicate: str, obj: str) -> bool:
    from datetime import date, timedelta

    # Parse the subject date
    try:
        subject_date = date.fromisoformat(subject)
    except ValueError:
        return False

    # Parse the number of days from the object
    try:
        days = int(obj)
    except ValueError:
        return False

    # Check that the predicate is 'days_after'
    if predicate.strip().lower() != 'days_after':
        return False

    # Compute today's date + days offset
    today = date.today()
