def verify(subject: str, predicate: str, obj: str) -> bool:
    from datetime import date, datetime

    # Parse the subject as a date (expected format: YYYY-MM-DD)
    try:
        subject_date = datetime.strptime(subject.strip(), "%Y-%m-%d").date()
    except ValueError:
        return False

    # Parse the object as the number of days
    try:
        days = int(obj.strip())
    except ValueError:
        return False

    # The predicate 'days_after' means: subject_date is `days` days after today
    today = date.today()
    delta = (subject_date - today).days

    return delta == days

