def verify(subject: str, predicate: str, obj: str) -> bool:
    import math

    # Parse the subject as an integer
    try:
        n = int(subject)
    except ValueError:
        return False

    # Determine the claimed result from the object
    claimed_prime = obj.strip().lower() == 'true'

    # Check primality via trial division
    def is_prime(num: int) -> bool:
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        for i in range(3, math.isqrt(num) + 1, 2):
            if num % i == 0:
                return False
        return True

    # The claim holds if the computed primality matches the claimed value
    return is_prime(n) == claimed_prime

def verify(subject: str, predicate: str, obj: str) -> bool:
    """
    Verifies that the sum of a comma-separated list of numbers (subject)
    equals the expected value (obj), when predicate is 'sum_equals'.
    """
    if predicate.strip().lower() != "sum_equals":
        return False

    # Parse the comma-separated numbers from subject
    try:
        numbers = [float(n.strip()) for n in subject.split(",")]
    except ValueError:
        return False

    # Parse the expected sum from obj
    try:
        expected = float(obj.strip())
    except ValueError:
        return False

    # Compare computed sum to expected value
    computed_sum = sum(numbers)
    return math.isclose(computed_sum, expected, rel_tol=1e-9)

def verify(subject: str, predicate: str, obj: str) -> bool:
    if predicate != "max_value":
        return False
    # Parse the subject as a comma-separated list of numbers
    numbers = [float(x.strip()) for x in subject.split(',')]
    # Compute the maximum value
    max_val = max(numbers)
    # Compare with the object value
    return max_val == float(obj.strip())
